script:
frappe.ui.form.on('Hostel Card', {
    refresh: function(frm) {
        if (frm.doc.card_status === 'Active') {
            frm.add_custom_button('Block Card', function() {
                frappe.prompt([
                    {fieldname: 'reason', label: 'Reason for Blocking', fieldtype: 'Small Text', reqd: 1}
                ], function(values) {
                    frappe.call({
                        method: 'hostel_card_action',
                        args: { action: 'block', card_name: frm.doc.name, reason: values.reason },
                        callback: function(r) {
                            frappe.msgprint(r.message.status);
                            frm.reload_doc();
                        }
                    });
                }, 'Block Card', 'Confirm');
            }, 'Actions');

            frm.add_custom_button('Expire Card', function() {
                frappe.confirm('Mark this card as Expired?', function() {
                    frappe.call({
                        method: 'hostel_card_action',
                        args: { action: 'expire', card_name: frm.doc.name },
                        callback: function(r) {
                            frappe.msgprint(r.message.status);
                            frm.reload_doc();
                        }
                    });
                });
            }, 'Actions');
        }

        if (frm.doc.card_status === 'Blocked' || frm.doc.card_status === 'Expired') {
            frm.add_custom_button('Reissue Card', function() {
                frappe.prompt([
                    {fieldname: 'reason', label: 'Reissue Reason (lost, damaged, etc.)', fieldtype: 'Small Text'}
                ], function(values) {
                    frappe.call({
                        method: 'hostel_card_action',
                        args: { action: 'reissue', card_name: frm.doc.name, reason: values.reason },
                        callback: function(r) {
                            frappe.msgprint(r.message.status);
                            frappe.set_route('Form', 'Hostel Card', r.message.new_card);
                        }
                    });
                }, 'Reissue Card', 'Create');
            }, 'Actions');
        }
    }
});
